def create_sns_subscription(topic_arn, endpoint_url, region_name="us-east-1"):
    """Create an SNS HTTPS subscription with validated endpoint."""

    # Validate the endpoint URL
    is_valid, message = validate_endpoint_url(endpoint_url)
    if not is_valid:
        print(f"ERROR: Endpoint validation failed: {message}")
        print("Subscription was NOT created.")
        return None

    # Validate topic ARN format
    if not re.match(r'^arn:aws:sns:[a-z0-9-]+:\d{12}:.+$', topic_arn):
        print("ERROR: Invalid SNS Topic ARN format.")
        return None

    try:
        sns_client = boto3.client("sns", region_name=region_name)

        response = sns_client.subscribe(
            TopicArn=topic_arn,
            Protocol="https",
            Endpoint=endpoint_url,
            ReturnSubscriptionArn=True,
        )

        subscription_arn = response.get("SubscriptionArn", "Pending confirmation")
        print(f"Subscription created successfully.")
        print(f"  Topic ARN: {topic_arn}")
        print(f"  Endpoint:  {endpoint_url}")
        print(f"  Subscription ARN: {subscription_arn}")
        return response

    except boto3.exceptions.Boto3Error as e:
        print(f"ERROR: Failed to create subscription: {e}")
        return None


def list_subscriptions(topic_arn, region_name="us-east-1"):
    """List all subscriptions for a given topic."""
    sns_client = boto3.client("sns", region_name=region_name)
    try:
        paginator = sns_client.get_paginator("list_subscriptions_by_topic")
        for page in paginator.paginate(TopicArn=topic_arn):
            for sub in page.get("Subscriptions", []):
                print(
                    f"  {sub['SubscriptionArn']} | {sub['Protocol']} | {sub['Endpoint']}"
                )
    except boto3.exceptions.Boto3Error as e:
        print(f"ERROR listing subscriptions: {e}")


def unsubscribe(subscription_arn, region_name="us-east-1"):
    """Remove an SNS subscription."""
    sns_client = boto3.client("sns", region_name=region_name)
    try:
        sns_client.unsubscribe(SubscriptionArn=subscription_arn)
        print(f"Unsubscribed: {subscription_arn}")
    except boto3.exceptions.Boto3Error as e:
        print(f"ERROR unsubscribing: {e}")


